// OrdersPage.js
import React, { useState, useEffect } from "react";
import "../index.css";

const OrdersPage = () => {
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    const storedOrders = JSON.parse(localStorage.getItem("orders")) || [];
    setOrders(storedOrders);
  }, []);

  const handleCancel = (id) => {
    const reason = prompt("Please enter a reason for cancellation:");
    if (!reason) return;

    const updatedOrders = orders.map((order) =>
      order.id === id ? { ...order, status: "Cancelled", cancelReason: reason } : order
    );

    setOrders(updatedOrders);
    localStorage.setItem("orders", JSON.stringify(updatedOrders));
  };

  if (orders.length === 0) {
    return <h2 style={{ textAlign: "center", marginTop: "50px" }}>No orders found 😔</h2>;
  }

  return (
    <div className="orders-page">
      <h2>Your Orders</h2>
      <div className="orders-list">
        {orders.map((order) => (
          <div key={order.id} className="order-card">
            <div className="order-header">
              <h3>Order #{order.id}</h3>
              <p>Date: {order.date}</p>
              <p>Status: <span className={order.status === "Cancelled" ? "cancelled" : "placed"}>{order.status}</span></p>
            </div>

            <div className="order-items">
              {order.items.map((item, i) => (
                <div key={i} className="order-item">
                  <img src={item.image} alt={item.name} />
                  <div>
                    <h4>{item.name}</h4>
                    <p>₹{item.price}</p>
                  </div>
                </div>
              ))}
            </div>

            <div className="order-footer">
              <p><strong>Total:</strong> ₹{order.total}</p>
              {order.status !== "Cancelled" && (
                <button onClick={() => handleCancel(order.id)} className="cancel-btn">Cancel Order</button>
              )}
              {order.status === "Cancelled" && (
                <p className="cancel-reason">Reason: {order.cancelReason}</p>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default OrdersPage;
